def shortestDistance(words, w1, w2):
    p1, p2, res = -1, -1, len(words)
    for i, w in enumerate(words):
        if w == w1: p1 = i
        if w == w2: p2 = i
        if p1 != -1 and p2 != -1: res = min(res, abs(p1-p2))
    return res

